import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        // [[1,4,5],[1,3,4],[2,6]] -> [1,1,2,3,4,4,5,6]
        // tie at value=1: src0 (idx 0) before src1 (idx 1)
        // tie at value=4: src0 (idx 0) before src1 (idx 1)
        assertArrayEquals(
            new int[]{1, 1, 2, 3, 4, 4, 5, 6},
            new Solution().mergeKSorted(new int[][]{{1,4,5},{1,3,4},{2,6}})
        );
    }

    @Test
    void singleSource() {
        // k=1: output must equal the single source unchanged
        assertArrayEquals(
            new int[]{2, 5, 9},
            new Solution().mergeKSorted(new int[][]{{2, 5, 9}})
        );
    }

    @Test
    void emptyInnerArray() {
        // src1 is empty — must not crash; output from src0 and src2 only
        assertArrayEquals(
            new int[]{1, 2, 3, 4},
            new Solution().mergeKSorted(new int[][]{{1, 2}, {}, {3, 4}})
        );
    }

    @Test
    void emptyOuterArray() {
        // no sources at all -> empty result
        assertArrayEquals(
            new int[]{},
            new Solution().mergeKSorted(new int[][]{})
        );
    }

    @Test
    void allSourcesSingleElement() {
        // each source contributes exactly one element
        assertArrayEquals(
            new int[]{1, 3, 5, 7},
            new Solution().mergeKSorted(new int[][]{{5},{1},{7},{3}})
        );
    }

    @Test
    void tiebreakerBySourceIndex() {
        // src0 has value 2, src1 has value 2, src2 has value 2
        // all equal -> sorted by source index ascending -> [2,2,2,10]
        assertArrayEquals(
            new int[]{2, 2, 2, 10},
            new Solution().mergeKSorted(new int[][]{{2,10},{2},{2}})
        );
    }

    @Test
    void largerMerge() {
        // three sources of length 3 each
        assertArrayEquals(
            new int[]{1, 2, 3, 4, 5, 6, 7, 8, 9},
            new Solution().mergeKSorted(new int[][]{{1,4,7},{2,5,8},{3,6,9}})
        );
    }
}
